import random
from typing import List, Optional
from task0 import Tetromino, TETROMINO_SHAPES

class TetrominoGenerator:
    def __init__(self):
        self.tetromino_types = list(TETROMINO_SHAPES.keys())
        self.bag = self.create_bag()

    def create_bag(self) -> List[str]:
        new_bag = self.tetromino_types[:]
        random.shuffle(new_bag)
        return new_bag

    def get_next_tetromino(self) -> Tetromino:
        if not self.bag:
            self.bag = self.create_bag()
        next_type = self.bag.pop()
        return TETROMINO_SHAPES[next_type]

class NextTetrominoPreview:
    def __init__(self, generator: TetrominoGenerator, preview_size: int = 4):
        self.generator = generator
        self.preview_size = preview_size
        self.next_tetromino: Optional[Tetromino] = None
        self.update_next_tetromino()

    def update_next_tetromino(self) -> None:
        self.next_tetromino = self.generator.get_next_tetromino()

    def get_preview_tetromino(self) -> Tetromino:
        if self.next_tetromino is None:
             self.update_next_tetromino()
        return self.next_tetromino
